// components/FloatingPanel.tsx
import { useEffect, useRef, useState } from 'react';

type Corner = 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';

export function FloatingPanel({ children }: { children: React.ReactNode }) {
  const [corner, setCorner] = useState<Corner>(() => {
    const stored = typeof window !== 'undefined' ? localStorage.getItem('panel-corner') : null;
    return (stored as Corner) ?? 'bottom-right';
  });
  const panelRef = useRef<HTMLDivElement>(null);

  const onPointerUp = (e: React.PointerEvent) => {
    const cx = e.clientX < window.innerWidth / 2 ? 'left' : 'right';
    const cy = e.clientY < window.innerHeight / 2 ? 'top' : 'bottom';
    const nextCorner = `${cy}-${cx}` as Corner;
    setCorner(nextCorner);
    localStorage.setItem('panel-corner', nextCorner);
  };

  const cornerClass = {
    'top-left': 'top-4 left-4',
    'top-right': 'top-4 right-4',
    'bottom-left': 'bottom-4 left-4',
    'bottom-right': 'bottom-4 right-4',
  }[corner];

  return (
    <div
      ref={panelRef}
      onPointerUp={onPointerUp}
      className={`fixed z-30 rounded-lg bg-white shadow-2xl p-3 ${cornerClass}`}
      style={{
        top: corner.startsWith('top') ? 'max(1rem, env(safe-area-inset-top))' : undefined,
        bottom: corner.startsWith('bottom') ? 'max(1rem, env(safe-area-inset-bottom))' : undefined,
        left: corner.endsWith('left') ? 'max(1rem, env(safe-area-inset-left))' : undefined,
        right: corner.endsWith('right') ? 'max(1rem, env(safe-area-inset-right))' : undefined,
      }}
    >{children}</div>
  );
}

