import { useState } from 'react';

export function SelectableCells() {
  const [selection, setSelection] = useState<{ start: number; end: number } | null>(null);

  const isSelected = (idx: number) => {
    if (!selection) return false;
    const min = Math.min(selection.start, selection.end);
    const max = Math.max(selection.start, selection.end);
    return idx >= min && idx <= max;
  };

  const handleClick = (idx: number, e: React.MouseEvent) => {
    if (e.shiftKey && selection) {
      setSelection({ ...selection, end: idx });
    } else {
      setSelection({ start: idx, end: idx });
    }
  };

  const handleKey = (e: React.KeyboardEvent, idx: number) => {
    if (!selection) return;
    if (e.shiftKey && (e.key === 'ArrowRight' || e.key === 'ArrowDown')) {
      e.preventDefault();
      setSelection({ ...selection, end: idx + 1 });
    }
  };

  return (
    <div className="grid grid-cols-5 gap-1">
      {Array.from({ length: 25 }).map((_, i) => (
        <button
          key={i}
          onClick={(e) => handleClick(i, e)}
          onKeyDown={(e) => handleKey(e, i)}
          tabIndex={0}
          className={`min-h-11 border ${isSelected(i) ? 'bg-blue-100 border-blue-400' : 'bg-white'}`}
        >{i}</button>
      ))}
    </div>
  );
}

// components/UsernameField.tsx
import { useEffect, useState } from 'react';
import { Check, X, Loader2 } from 'lucide-react';

export function UsernameField({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  const [status, setStatus] = useState<'idle' | 'checking' | 'available' | 'taken'>('idle');

  useEffect(() => {
    if (!value || value.length < 3) { setStatus('idle'); return; }
    setStatus('checking');
    const t = setTimeout(async () => {
      try {
        const res = await fetch(`/api/username-check?username=${encodeURIComponent(value)}`);
        const { available } = await res.json();
        setStatus(available ? 'available' : 'taken');
      } catch {
        setStatus('idle');
      }
    }, 500);
    return () => clearTimeout(t);
  }, [value]);

  const Icon = status === 'checking' ? Loader2 : status === 'available' ? Check : status === 'taken' ? X : null;
  const color = status === 'available' ? 'text-green-600' : status === 'taken' ? 'text-red-600' : 'text-neutral-400';

  return (
    <label className="block">
      <span className="text-sm font-medium">Username</span>
      <div className="relative mt-1">
        <input
          type="text"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          autoComplete="username"
          aria-describedby="username-status"
          className="block w-full min-h-11 rounded border pl-3 pr-10 text-base"
        />
        {Icon && <Icon className={`absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 ${color} ${status === 'checking' ? 'animate-spin' : ''}`} aria-hidden />}
      </div>
      <p id="username-status" aria-live="polite" className={`mt-1 text-xs min-h-[1rem] ${color}`}>
        {status === 'available' && 'Username available'}
        {status === 'taken' && 'Username taken'}
        {status === 'checking' && 'Checking...'}
      </p>
    </label>
  );
}

