    const onKey = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key === 'ArrowLeft' || e.key === 'j') prev && router.push(prev.href);
      if (e.key === 'ArrowRight' || e.key === 'k') next && router.push(next.href);
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [prev, next, router]);

  return (
    <nav aria-label="Article pagination" className="flex justify-between gap-4 mt-8 pt-8 border-t">
      {prev ? (
        <Link href={prev.href} className="flex items-center gap-2 min-h-11 px-3 hover:text-blue-600">
          <ChevronLeft className="h-4 w-4" />
          <div>
            <div className="text-xs text-neutral-500">Previous</div>
            <div className="font-medium">{prev.title}</div>
          </div>
        </Link>
      ) : <span />}
      {next ? (
        <Link href={next.href} className="flex items-center gap-2 min-h-11 px-3 hover:text-blue-600 text-right">
          <div>
            <div className="text-xs text-neutral-500">Next</div>
            <div className="font-medium">{next.title}</div>
          </div>
          <ChevronRight className="h-4 w-4" />
        </Link>
      ) : <span />}
    </nav>
  );
}
